  % خط طلایی بالا
  \draw[PrimaryGold, line width=1pt] 
    ([xshift=40mm, yshift=-50mm]current page.north west) -- 
    ([xshift=-40mm, yshift=-50mm]current page.north east);

  % عنوان اصلی
