    انتخابات رسمی قانون اساسی}};

  % نام نویسنده
  \node[
    anchor=south,
    text=PrimaryGold,
    font=\Large\bfseries
  ] at ([yshift=50mm]current page.south) 
    {[نام نویسنده / نویسندگان]};

