\part{مبانی نظری گذار دموکراتیک}

% ============================================================
% فصل ۱ — مقدمه و چارچوب مفهومی
% ============================================================
\chapter{مقدمه و چارچوب مفهومی}

\section{تعریف گذار دموکراتیک}

گذار دموکراتیک (\lr{Democratic Transition}) به فرآیندی اشاره 
دارد که طی آن یک نظام سیاسی اقتدارگرا به سوی نظامی 
دموکراتیک حرکت می‌کند. این فرآیند شامل مراحل مختلفی 
است که مهم‌ترین آن‌ها \textbf{دورهٔ گذار} 
(\lr{Transition Period}) است.

\begin{theorybox}{تعریف ساموئل هانتینگتون}
هانتینگتون گذار دموکراتیک را فرآیندی می‌داند که در آن 
«یک رژیم غیردموکراتیک با یک نظام دموکراتیک جایگزین 
می‌شود، به‌گونه‌ای که قدرت سیاسی به شکل مسالمت‌آمیز و 
از طریق انتخابات آزاد منتقل شود.»\\[2mm]
\hfill — \lr{The Third Wave, 1991}
\end{theorybox}

\subsection{مراحل گذار}

گذار سیاسی را می‌توان به چهار مرحلهٔ اصلی تقسیم کرد:

\begin{enumerate}[label=\textcolor{PrimaryGold}{\arabic*.}, 
  itemsep=3mm, font=\bfseries]
\item \textbf{مرحلهٔ پیشاگذار (فروپاشی نظام قبلی):} 
شامل بحران مشروعیت، اعتراضات، شکاف در نخبگان 
حاکم و سرانجام سقوط رژیم.
\item \textbf{مرحلهٔ گذار (موضوع اصلی این کتاب):} از 
لحظهٔ سقوط نظام تا استقرار نهادهای دموکراتیک جدید و 
برگزاری نخستین انتخابات.
\item \textbf{مرحلهٔ تثبیت دموکراسی:} استحکام نهادها، 
توسعهٔ فرهنگ دموکراتیک و حاکمیت قانون.
\item \textbf{مرحلهٔ نهادینه‌سازی:} درونی‌شدن ارزش‌های 
دموکراتیک در جامعه و بازی سیاسی.
\end{enumerate}

