\section{نظریهٔ گذار اودانل و اشمیتر}

\begin{theorybox}{چارچوب اودانل و اشمیتر}
گیلرمو اودانل و فیلیپ اشمیتر در اثر مرجع خود 
\lr{Transitions from Authoritarian Rule (1986)} 
چارچوبی چهاربخشی برای تحلیل گذارها ارائه دادند:
\begin{enumerate}[itemsep=2mm]
\item \textbf{لیبرالیزاسیون:} گشایش فضای سیاسی توسط نظام 
اقتدارگرا (یا فروپاشی آن).
\item \textbf{دموکراتیزاسیون:} ایجاد نهادها و قواعد دموکراتیک.
\item \textbf{مشارکت‌سازی:} گسترش حوزهٔ مشارکت سیاسی به 
گروه‌های مختلف اجتماعی.
\item \textbf{تثبیت:} نهادینه‌شدن قواعد بازی دموکراتیک.
\end{enumerate}
\end{theorybox}

\section{نظریهٔ خوان لینتز و آلفرد استپان}

\begin{theorybox}{پنج عرصهٔ تثبیت دموکراسی — لینتز و استپان}
لینتز و استپان پنج عرصهٔ ضروری برای تثبیت دموکراسی 
تعریف کردند:
\begin{enumerate}[itemsep=2mm]
\item \textbf{جامعهٔ مدنی آزاد و پویا}
\item \textbf{جامعهٔ سیاسی نسبتاً خودمختار و ارزشمند}
\item \textbf{حاکمیت قانون}
\item \textbf{دستگاه دولتی کارآمد}
\item \textbf{جامعهٔ اقتصادی نهادینه‌شده}
\end{enumerate}
\hfill — \lr{Problems of Democratic Transition and 
Consolidation, 1996}
\end{theorybox}

