\chapter{گذارهای موفق: درس‌آموزی از بهترین‌ها}

\section{اسپانیا (۱۹۷۵–۱۹۷۸)}

\begin{casestudy}{اسپانیا — الگوی گذار مذاکره‌ای}
\textbf{نوع گذار:} مذاکره و توافق نخبگان\\
\textbf{مدت دوران گذار:} ۳ سال (۱۹۷۵–۱۹۷۸)\\
\textbf{نتیجه:} \textcolor{AccentGreen}{موفق — دموکراسی 
تثبیت‌شده}\\[3mm]

پس از مرگ ژنرال فرانکو در نوامبر ۱۹۷۵، اسپانیا یکی از 
موفق‌ترین گذارهای دموکراتیک تاریخ را تجربه کرد. شاه 
خوان‌کارلوس اول، آدولفو سوآرس را به نخست‌وزیری منصوب 
کرد و فرآیند دموکراتیزاسیون آغاز شد.

\textbf{عوامل کلیدی موفقیت:}
\begin{itemize}[itemsep=1mm]
\item پیمان مونکلوآ: توافق میان تمامی نیروهای سیاسی
\item نقش تعادل‌بخش پادشاهی
\item عفو عمومی و نگاه به آینده
\item عضویت در جامعهٔ اروپایی به‌عنوان انگیزه
\item رشد طبقهٔ متوسط و جامعهٔ مدنی
\end{itemize}
\end{casestudy}

