\section{لهستان (۱۹۸۹–۱۹۹۱)}

\begin{casestudy}{لهستان — الگوی میز گرد}
\textbf{نوع گذار:} مذاکره (میز گرد) + انقلاب مخملی\\
\textbf{مدت دوران گذار:} ۲ سال (۱۹۸۹–۱۹۹۱)\\
\textbf{نتیجه:} \textcolor{AccentGreen}{موفق — دموکراسی 
تثبیت‌شده}\\[3mm]

مذاکرات میز گرد لهستان میان حزب کمونیست حاکم و جنبش 
همبستگی (\lr{Solidarity}) به رهبری لخ والسا، الگویی بی‌نظیر 
از گذار مسالمت‌آمیز ارائه داد.

\textbf{عوامل کلیدی موفقیت:}
\begin{itemize}[itemsep=1mm]
\item جنبش همبستگی به‌عنوان چتر فراگیر اپوزیسیون
\item نقش کلیسای کاتولیک در میانجی‌گری
\item فشار اقتصادی و ناکارآمدی نظام سوسیالیستی
\item تغییرات ژئوپلیتیکی (گورباچف و گلاسنوست)
\item رهبری کاریزماتیک والسا
\end{itemize}
\end{casestudy}

\section{آفریقای جنوبی (۱۹۹۰–۱۹۹۴)}

\begin{casestudy}{آفریقای جنوبی — الگوی آشتی ملی}
\textbf{نوع گذار:} مذاکره و آشتی ملی\\
\textbf{مدت دوران گذار:} ۴ سال (۱۹۹۰–۱۹۹۴)\\
\textbf{نتیجه:} \textcolor{AccentGreen}{موفق — با چالش‌های 
باقی‌مانده}\\[3mm]

آزادی نلسون ماندلا در فوریهٔ ۱۹۹۰ سرآغاز یکی از 
الهام‌بخش‌ترین فرآیندهای گذار بود. کمیسیون حقیقت و 
آشتی (\lr{TRC}) به ریاست اسقف دزموند توتو، الگویی جهانی 
برای عدالت انتقالی شد.

\textbf{درس‌های کلیدی برای ایران:}
\begin{itemize}[itemsep=1mm]
\item آشتی ملی مقدم بر انتقام‌جویی
\item کمیسیون حقیقت‌یاب به‌جای دادگاه‌های انقلابی
\item قانون اساسی فراگیر با حفظ حقوق اقلیت‌ها
\item بازتوزیع تدریجی قدرت اقتصادی
\end{itemize}
\end{casestudy}

\section{تونس (۲۰۱۱–۲۰۱۴)}

\begin{casestudy}{تونس — تنها موفقیت بهار عربی}
\textbf{نوع گذار:} انقلاب مردمی + مذاکره\\
\textbf{مدت دوران گذار:} ۳ سال (۲۰۱۱–۲۰۱۴)\\
\textbf{نتیجه:} \textcolor{AccentOrange}{نسبتاً موفق — تا 
پیش از بازگشت اقتدارگرایی ۲۰۲۱}\\[3mm]

تونس تنها کشور بهار عربی بود که توانست به دموکراسی 
گذار کند. چهارتای گفتگوی ملی (\lr{National Dialogue 
Quartet}) نقشی تعیین‌کننده در میانجی‌گری میان اسلام‌گرایان 
و سکولارها ایفا کرد و برندهٔ جایزهٔ صلح نوبل ۲۰۱۵ شد.

\textbf{عوامل موفقیت:}
\begin{itemize}[itemsep=1mm]
\item جامعهٔ مدنی قوی و سنت سندیکایی
\item ارتش غیرسیاسی و حرفه‌ای
\item همگنی نسبی قومی و مذهبی
\item انعطاف‌پذیری حزب النهضه (اسلام‌گرا)
\item نقش میانجی‌گرانهٔ جامعهٔ مدنی
\end{itemize}

\textbf{دلایل شکست نهایی (پس از ۲۰۲۱):}
\begin{itemize}[itemsep=1mm]
\item بحران اقتصادی مزمن و بیکاری بالا
\item ناتوانی در پاسخگویی به مطالبات اقتصادی مردم
\item فساد سیاسی و بن‌بست پارلمانی
\item ضعف فرهنگ دموکراتیک
\end{itemize}
\end{casestudy}

% ============================================================
% فصل ۴ — گذارهای ناموفق
% ============================================================
\chapter{گذارهای ناموفق: چه نباید کرد؟}

\section{عراق (۲۰۰۳–۲۰۰۵)}

\begin{casestudy}{عراق — فاجعهٔ مهندسی بیرونی}
\textbf{نوع گذار:} مداخلهٔ نظامی خارجی\\
\textbf{مدت دوران گذار:} ۲ سال (رسمی) / ادامه‌دار\\
\textbf{نتیجه:} \textcolor{AccentRed}{ناموفق — بی‌ثباتی مزمن}\\[3mm]

تجربهٔ عراق آموزنده‌ترین درس منفی برای ایران است. انحلال 
ارتش و حزب بعث (\lr{De-Baathification})، خلأ امنیتی 
گسترده‌ای ایجاد کرد. نظام سهمیه‌ای (\lr{Muhasasa}) 
قومی-مذهبی به فساد سیستماتیک انجامید.

\textbf{خطاهای اساسی:}
\begin{itemize}[itemsep=1mm]
\item \redcircle\ انحلال کامل ارتش و دستگاه امنیتی
\item \redcircle\ بعث‌زدایی افراطی و حذف کامل نخبگان قبلی
\item \redcircle\ تحمیل نظام سهمیه‌ای قومی-مذهبی
\item \redcircle\ بی‌توجهی به بافت اجتماعی و قبیله‌ای
\item \redcircle\ نبود برنامهٔ اقتصادی پس از جنگ
\item \redcircle\ وابستگی به قدرت خارجی
\end{itemize}
\end{casestudy}

\begin{warningbox}
\textbf{هشدار برای ایران:} انحلال یکبارهٔ سپاه پاسداران بدون 
برنامهٔ جامع ادغام و خلع‌سلاح، می‌تواند فاجعه‌ای مشابه 
عراق ایجاد کند. هزاران نیروی مسلح بیکار و ناامید، 
بزرگ‌ترین تهدید امنیتی دوران گذار خواهند بود.
\end{warningbox}

\section{لیبی (۲۰۱۱–ادامه‌دار)}

\begin{casestudy}{لیبی — فروپاشی دولت}
\textbf{نوع گذار:} انقلاب مسلحانه + مداخلهٔ خارجی\\
\textbf{مدت دوران گذار:} ادامه‌دار (بیش از ۱۳ سال)\\
\textbf{نتیجه:} \textcolor{AccentRed}{فاجعه‌بار — دولت 
شکست‌خورده}\\[3mm]

سقوط قذافی در اکتبر ۲۰۱۱ به‌جای آغاز دموکراسی، سرآغاز 
جنگ داخلی و تجزیهٔ عملی لیبی شد.

\textbf{دلایل شکست:}
\begin{itemize}[itemsep=1mm]
\item نبود نهادهای دولتی (قذافی دولت را شخصی‌سازی کرده بود)
\item شکاف‌های قبیله‌ای عمیق
\item انبوه سلاح و شبه‌نظامیان
\item رقابت قدرت‌های منطقه‌ای و بین‌المللی
\item فقدان جامعهٔ مدنی و احزاب سیاسی
\end{itemize}
\end{casestudy}

\section{مصر (۲۰۱۱–۲۰۱۳)}

\begin{casestudy}{مصر — دموکراسی کوتاه‌مدت}
\textbf{نوع گذار:} انقلاب مردمی\\
\textbf{مدت دوران گذار:} ۲ سال (۲۰۱۱–۲۰۱۳)\\
\textbf{نتیجه:} \textcolor{AccentRed}{ناموفق — بازگشت 
اقتدارگرایی نظامی}\\[3mm]

مصر نشان داد که حتی انقلاب مردمی باشکوه هم بدون مدیریت 
صحیح گذار، به شکست می‌انجامد. دلایل عمده:

\begin{itemize}[itemsep=1mm]
\item اقتدار ارتش و عدم تبعیت از غیرنظامیان
\item استقطاب شدید میان اسلام‌گرایان و سکولارها
\item عجله در برگزاری انتخابات بدون آمادگی نهادی
\item ناتوانی اخوان‌المسلمین در حکمرانی فراگیر
\item بحران اقتصادی و ناامیدی عمومی
\end{itemize}
\end{casestudy}

