\begin{recommendation}
\textbf{اقدامات فوری ۷۲ ساعت اول:}
\begin{enumerate}[itemsep=2mm, label=\textcolor{PrimaryGold}{\arabic*.}]
\item \textbf{اعلام حکومت موقت/شورای انتقالی:} 
