\section{تحلیل ریسک‌های بحرانی}

\subsection{ریسک ۱: جنگ داخلی و تجزیه}

\begin{warningbox}
\textbf{بدترین سناریو:} در غیاب مدیریت صحیح، ایران 
می‌تواند با سناریوی «سوریه‌ای‌شدن» مواجه شود: جنگ‌های 
نیابتی، مداخلهٔ همسایگان، و تجزیهٔ عملی سرزمین.

\textbf{عوامل تشدید‌کننده:}
\begin{itemize}[itemsep=1mm]
\item دسترسی گسترده به سلاح (سپاه، بسیج)
\item مرزهای طولانی با کشورهای ناامن
\item وجود گروه‌های تجزیه‌طلب فعال
\item رقابت قدرت‌های منطقه‌ای (عربستان، ترکیه، اسرائیل)
\item ضعف هویت ملی فراقومی در برخی مناطق
\end{itemize}
\end{warningbox}

\begin{recommendation}
\textbf{راهکارهای مقابله:}
\begin{enumerate}[itemsep=2mm, label=\textcolor{PrimaryGold}{\bfseries\arabic*.}]
\item \textbf{اعلام فوری پیمان ملی:} تمامی گروه‌های سیاسی و 
قومی بر حفظ یکپارچگی سرزمینی توافق کنند.
\item \textbf{پیشنهاد فدرالیسم یا عدم تمرکز:} پاسخ‌گویی به 
مطالبات قومی بدون تجزیه.
\item \textbf{حفظ ساختار ارتش:} ارتش ملی (نه سپاه) به‌عنوان 
ضامن یکپارچگی.
\item \textbf{دیپلماسی فعال:} تعهدگیری از همسایگان برای عدم 
مداخله.
\item \textbf{توزیع عادلانهٔ منابع:} رفع تبعیض اقتصادی مناطق 
محروم.
\end{enumerate}
\end{recommendation}

\subsection{ریسک ۲: کودتای بازگشتی}

\begin{warningbox}
تجربهٔ مصر نشان داد که ارتش می‌تواند فرآیند دموکراتیزاسیون 
را معکوس کند. در ایران، سپاه پاسداران با توان نظامی، 
اقتصادی و اطلاعاتی گسترده، قادر به کودتا هست.
\end{warningbox}

\begin{recommendation}
\textbf{راهکارهای پیشگیری:}
\begin{enumerate}[itemsep=2mm, label=\textcolor{PrimaryGold}{\bfseries\arabic*.}]
\item \textbf{ادغام تدریجی نه انحلال ناگهانی:} از تجربهٔ عراق 
درس بگیریم.
\item \textbf{بازنشستگی آبرومندانه:} بستهٔ بازنشستگی سخاوتمندانه 
برای فرماندهان ارشد.
\item \textbf{گارانتی امنیت جانی و مالی:} تضمین عدم تعقیب 
ردهٔ‌پایین‌ها.
\item \textbf{بین‌المللی‌سازی فرآیند:} حضور ناظران بین‌المللی.
\item \textbf{ایجاد وفاداری نهادی:} ارتقای نظامیان حرفه‌ای و 
غیرسیاسی.
\end{enumerate}
\end{recommendation}

