\begin{enumerate}[itemsep=2mm, label=\textcolor{PrimaryGold}{\bfseries\arabic*.}]
\item \textbf{تثبیت نرخ ارز:} مداخلهٔ بانک مرکزی + وام 
بین‌المللی اضطراری.
\item \textbf{رفع تحریم‌ها:} مذاکرهٔ فوری با آمریکا و اتحادیهٔ 
اروپا.
\item \textbf{بازگشایی حساب‌های مسدود:} دسترسی به ذخایر ارزی 
ایران.
\item \textbf{کمک‌های بین‌المللی:} درخواست از صندوق بین‌المللی 
پول و بانک جهانی.
\item \textbf{حمایت از معیشت مردم:} سبد کالا و یارانهٔ نقدی 
اضطراری.
\item \textbf{حفاظت از زیرساخت‌های نفتی:} تداوم تولید و صادرات.
\item \textbf{جلب سرمایهٔ دیاسپورا:} بستهٔ تشویقی برای سرمایه‌گذاری.
\end{enumerate}
\end{recommendation}

