\chapter{توصیه‌های نهایی و جمع‌بندی}

\section{ده فرمان دوران گذار}

\begin{tcolorbox}[
  enhanced,
  colback=PrimaryNavy!3,
  colframe=PrimaryGold,
  fonttitle=\bfseries\Large,
  coltitle=PrimaryNavy,
  title={\hfill ده فرمان دوران گذار ایران \hfill},
  attach boxed title to top center={yshift=-3mm},
  boxed title style={
    colback=PrimaryGold!80, rounded corners,
    boxrule=0pt
  },
  arc=8mm,
  boxrule=2pt,
  left=8mm, right=8mm, top=8mm, bottom=8mm,
  shadow={3mm}{-2mm}{0mm}{black!20}
]

\begin{enumerate}[
  itemsep=4mm,
  label={\begin{tikzpicture}[baseline=(n.base)]
    \node[
      circle, fill=PrimaryGold, text=white,
      minimum size=8mm, font=\bfseries,
      inner sep=0pt
    ] (n) {\arabic*};
  \end{tikzpicture}},
  leftmargin=15mm
]

\item \textbf{وحدت بر انتقام مقدم است.} 
آشتی ملی کلید بقای ایران یکپارچه است. 
از تجربهٔ آفریقای جنوبی بیاموزیم.

\item \textbf{ادغام کن، منحل نکن.} 
سپاه را ادغام کنید، نه منحل. از فاجعهٔ 
بعث‌زدایی عراق درس بگیرید.

\item \textbf{اول امنیت، بعد دموکراسی.} 
بدون ثبات امنیتی، هیچ انتخاباتی معنادار 
نخواهد بود. ابتدا نظم، سپس آزادی.

\item \textbf{اقتصاد را فراموش نکن.} 
مردم نان هم می‌خواهند. بدون بهبود معیشت، 
حمایت مردمی از دست می‌رود (درس مصر و تونس).

\item \textbf{همه را سر میز بنشان.} 
هیچ گروه مهمی نباید از فرآیند حذف شود. 
حذف‌شدگان، اخلال‌گران فردا هستند.

\item \textbf{عجله نکن، اما دیر هم نکن.} 
انتخابات زودهنگام (مصر) و تأخیر بی‌دلیل هر 
دو خطرناک‌اند. زمان‌بندی ۱۲ ماهه بهینه است.

\item \textbf{زنان را در مرکز بگذار.} 
زنان ایرانی موتور محرک جنبش‌های اخیرند. 
برابری جنسیتی باید اصل بنیادین قانون اساسی باشد.

\item \textbf{تنوع را بپذیر، تجزیه را رد کن.} 
عدم تمرکز و حکمرانی محلی پاسخی عادلانه به 
مطالبات قومی بدون خطر تجزیه است.

\item \textbf{بین‌المللی فکر کن.} 
رفع تحریم‌ها، عضویت در نهادهای بین‌المللی و 
بازگشت به جامعهٔ جهانی اولویت اقتصادی و 
سیاسی دارد.

\item \textbf{از

```latex
 تاریخ خودت بیاموز.} 
مشروطه، ملی‌شدن نفت، و انقلاب ۵۷ — هر سه 
درس‌هایی گرانبها دارند. تاریخ تکرار می‌شود، 
اگر درسش را نیاموزیم.

\end{enumerate}
\end{tcolorbox}

