\section{اصول سیاست خارجی ایران نوین}

\begin{tcolorbox}[
  enhanced,
  colback=SteelBlue!3,
  colframe=SteelBlue,
  fonttitle=\bfseries\large,
  coltitle=white,
  title={\hfill دکترین سیاست خارجی ایران نوین \hfill},
  attach boxed title to top center={yshift=-3mm},
  boxed title style={colback=SteelBlue, rounded corners},
  arc=5mm,
  boxrule=1.5pt,
  left=6mm, right=6mm
]
\begin{enumerate}[
  itemsep=4mm,
  label={\textcolor{SteelBlue}{\bfseries\Roman*.}},
  leftmargin=10mm
]
\item \textbf{تنش‌زدایی منطقه‌ای:} پایان سیاست صدور انقلاب، 
تبدیل ایران از تهدید منطقه‌ای به شریک توسعه‌ای.

\item \textbf{سیاست همسایگی مثبت:} برقراری روابط عادی با 
تمام همسایگان، از جمله عربستان و اسرائیل (بر اساس منافع ملی).

\item \textbf{بازگشت به جامعهٔ جهانی:} عضویت فعال در 
سازمان ملل، WTO، و نهادهای بین‌المللی.

\item \textbf{ائتلاف با دموکراسی‌ها:} نزدیکی استراتژیک با 
اتحادیهٔ اروپا، ژاپن، کره جنوبی و هند.

\item \textbf{اقتصاد‌محوری:} تبدیل دیپلماسی از ایدئولوژیک 
به اقتصاد‌محور.

\item \textbf{بی‌طرفی فعال:} اجتناب از بلوک‌بندی‌های نظامی، 
حفظ روابط متوازن با شرق و غرب.

\item \textbf{حقوق بشر‌محوری:} تعهد به معاهدات بین‌المللی 
حقوق بشر.

\item \textbf{همکاری امنیتی منطقه‌ای:} مشارکت در طرح‌های 
امنیت جمعی خلیج فارس.
\end{enumerate}
\end{tcolorbox}


