\section{احزاب کردی}

کردها فعال‌ترین و سازمان‌یافته‌ترین اقلیت قومی ایران 
هستند. چندین حزب مهم با مواضع متفاوت وجود دارد:

\subsection{حزب دموکرات کردستان ایران (KDPI)}

\begin{casestudy}{حزب دموکرات کردستان ایران}
\textbf{تأسیس:} ۱۳۲۴ (۱۹۴۵) — قدیمی‌ترین حزب کردی ایران\\
\textbf{رهبری:} مصطفی هجری (دبیرکل)\\
\textbf{طیف:} مرکز-چپ / سوسیال‌دموکرات\\
\textbf{موقعیت:} تبعید (اقلیم کردستان عراق)\\
\textbf{ظرفیت نظامی:} \textcolor{AccentRed}{دارای نیروی 
پیشمرگ (چند هزار نفر)}\\
\textbf{پایگاه اجتماعی:} کردهای سنندج، مهاباد، بوکان\\
\textbf{حامیان خارجی:} اقلیم کردستان عراق (KDP)\\[3mm]

\textbf{مواضع کلیدی:}
\begin{itemize}[itemsep=1mm]
\item \yellowcircle\ «فدرالیسم برای ایران، خودمختاری برای 
کردستان» — شعار رسمی
\item \yellowcircle\ اعلام تعهد به یکپارچگی ایران \textbf{مشروط 
به} حقوق اقلیت‌ها
\item حق تحصیل و رسانه به زبان کردی
\item مشارکت عادلانه در قدرت سیاسی
\item توسعهٔ اقتصادی مناطق کردنشین
\end{itemize}

\textbf{نقاط بحث‌برانگیز:}
\begin{itemize}[itemsep=1mm]
\item \yellowcircle\ ابهام در تعریف «خودمختاری» (چه سطحی؟)
\item \yellowcircle\ وجود نیروی مسلح — چالش DDR
\item \yellowcircle\ روابط پیچیده با احزاب کردی عراق و ترکیه
\item \yellowcircle\ تاریخ جمهوری مهاباد (۱۳۲۴) — الهام‌بخش 
یا تجزیه‌طلبانه؟
\end{itemize}

\textbf{ارزیابی آمادگی ائتلاف:} متوسط — مشروط به پذیرش 
فدرالیسم توسط ائتلاف ملی
\end{casestudy}

\subsection{کومله (سازمان انقلابی زحمتکشان کردستان)}

\begin{casestudy}{کومله}
\textbf{تأسیس:} ۱۳۴۸ (۱۹۶۹)\\
\textbf{طیف:} چپ / مارکسیست (تحول‌یافته)\\
\textbf{رهبری:} عبدالله مهتدی (دبیرکل — شاخهٔ اصلی)\\
\textbf{موقعیت:} تبعید (اقلیم کردستان عراق)\\
\textbf{ظرفیت نظامی:} \textcolor{AccentOrange}{نیروی پیشمرگ 
محدود}\\[3mm]

\textbf{تحول مهم:} عبدالله مهتدی از شخصیت‌های فعال در 
ائتلاف‌سازی اپوزیسیون ایران بوده و در «جورج‌تاون» و سایر 
نشست‌های اپوزیسیون حضور داشته است.

\textbf{مواضع:}
\begin{itemize}[itemsep=1mm]
\item \yellowcircle\ فدرالیسم دموکراتیک
\item \greencircle\ آمادگی نسبتاً بالا برای ائتلاف ملی
\item عدالت اجتماعی + حقوق قومی
\item نزدیکی به گفتمان سوسیال‌دموکراتیک اروپایی
\end{itemize}

\textbf{نقطهٔ قوت:} انعطاف‌پذیری سیاسی بیشتر از PJAK\\
\textbf{نقطهٔ ضعف:} انشعابات متعدد
\end{casestudy}

\subsection{حزب حیات آزاد کردستان (PJAK)}

\begin{casestudy}{PJAK — شاخهٔ ایرانی PKK}
\textbf{تأسیس:} ۱۳۸۳ (۲۰۰۴)\\
\textbf{طیف:} چپ رادیکال / آپوئیست\\
\textbf{موقعیت:} مناطق مرزی (قندیل)\\
\textbf{ظرفیت نظامی:} \textcolor{AccentRed}{نیروی مسلح فعال}\\
\textbf{ایدئولوژی:} کنفدرالیسم دموکراتیک (آبدالله اوجالان)\\[3mm]

\textbf{مواضع کلیدی:}
\begin{itemize}[itemsep=1mm]
\item \redcircle\ «خودمختاری دموکراتیک» — ابهام در معنای 
عملی
\item \redcircle\ پیوند ارگانیک با PKK (سازمان تروریستی از 
نظر ترکیه، آمریکا و اتحادیهٔ اروپا)
\item \yellowcircle\ ادعای عدم تجزیه‌طلبی — اما چارچوب 
ایدئولوژیک مبهم
\item تأکید بر حقوق زنان و اکولوژی
\end{itemize}

\textbf{چالش اصلی:} PJAK به‌دلیل پیوند با PKK، مشکل‌ساز‌ترین 
بازیگر قومی-نظامی است. هرگونه توافق با PJAK باید 
تأثیرات منطقه‌ای (ترکیه، عراق) را لحاظ کند.
\end{casestudy}

