\section{جنبش ملی آذربایجان جنوبی}

\begin{casestudy}{جنبش آذری — پیچیده‌ترین مسئلهٔ قومی}
\textbf{ماهیت:} مجموعه‌ای از گروه‌ها و فعالان (نه یک حزب 
واحد)\\
\textbf{طیف:} از حقوق فرهنگی تا تجزیه‌طلبی\\
\textbf{شخصیت‌های شاخص:} محمود علی‌چهرگانی (†)، عباس 
لسانی (زندانی سیاسی)، محمدرضا هیئت\\
\textbf{پایگاه اجتماعی:} بخشی از آذری‌های ایران (به‌ویژه 
فعالان فرهنگی)\\
\textbf{ظرفیت نظامی:} ندارد\\[3mm]

\textbf{طیف مطالبات:}
\begin{enumerate}[itemsep=1mm]
\item \greencircle\ \textbf{گرایش اکثریتی (حقوق فرهنگی):} 
آموزش ترکی، رسانهٔ ترکی، رفع تبعیض — بدون تجزیه‌طلبی
\item \yellowcircle\ \textbf{گرایش فدرالیستی:} خودمختاری ایالتی 
در چارچوب ایران
\item \redcircle\ \textbf{گرایش پان‌ترکیستی (اقلیتی):} الحاق 
به جمهوری آذربایجان یا تشکیل «آذربایجان بزرگ»
\end{enumerate}

\textbf{عوامل تشدید‌کننده:}
\begin{itemize}[itemsep=1mm]
\item سیاست‌های پان‌ترکیستی جمهوری آذربایجان (علی‌اف)
\item نفوذ ترکیه (اردوغان و گفتمان «جهان ترک»)
\item تحقیر فرهنگی تاریخی آذری‌ها در رسانه‌های فارسی‌زبان
\item تبعیض اقتصادی مناطق آذری‌نشین
\end{itemize}

\textbf{عوامل تعدیل‌کننده:}
\begin{itemize}[itemsep=1mm]
\item \greencircle\ آذری‌ها بزرگ‌ترین اقلیت (≈۱۶\%) و 
عمیقاً در ساختار ملی ایران ادغام شده‌اند
\item \greencircle\ بسیاری از رهبران تاریخی ایران آذری بوده‌اند
\item \greencircle\ ازدواج‌های بین‌قومی گسترده (به‌ویژه با فارس‌ها)
\item \greencircle\ اکثریت آذری‌ها خود را ایرانی می‌دانند
\end{itemize}
\end{casestudy}

\begin{recommendation}
\textbf{راهبرد پیشنهادی برای مسئلهٔ آذری:}
\begin{enumerate}[itemsep=2mm, label=\textcolor{PrimaryGold}{\bfseries\arabic*.}]
\item آموزش رسمی زبان ترکی از دبستان تا دانشگاه
\item شبکهٔ تلویزیونی سراسری ترکی‌زبان
\item ایالت آذربایجان با شورای محلی منتخب
\item توسعهٔ اقتصادی ویژه (خصوصاً تبریز به‌عنوان قطب صنعتی)
\item حمایت دیپلماتیک: جلوگیری از مداخلهٔ باکو و آنکارا
\item \textbf{مهم‌ترین تدبیر:} مشارکت آذری‌ها در رهبری ملی 
(حضور مؤثر در شورای انتقالی و مجلس مؤسسان)
\end{enumerate}
\end{recommendation}

\section{جنبش‌های عربی خوزستان}

\begin{casestudy}{جنبش‌های عربی — حساس و پیچیده}
\textbf{ماهیت:} چندین گروه و سازمان پراکنده\\
\textbf{طیف:} از حقوق فرهنگی تا تجزیه‌طلبی (الأحوازیه)\\
\textbf{پایگاه:} اعراب خوزستان (≈ ۲ میلیون نفر)\\
\textbf{ظرفیت نظامی:} \textcolor{AccentOrange}{برخی گروه‌ها 
مسلح (محدود)}\\[3mm]

\textbf{مطالبات اصلی:}
\begin{itemize}[itemsep=1mm]
\item رفع محرومیت شدید اقتصادی خوزستان (پارادوکس: 
غنی‌ترین استان از نظر نفت، فقیرترین از نظر توسعه)
\item حقوق زبانی و فرهنگی
\item رفع تبعیض استخدامی (صنعت نفت عمدتاً غیربومی)
\item حل بحران آب و محیط زیست (ریزگردها، تخریب تالاب‌ها)
\end{itemize}

\textbf{نقاط بحث‌برانگیز:}
\begin{itemize}[itemsep=1mm]
\item \redcircle\ حمایت برخی دولت‌های عربی (عربستان، امارات) 
از گروه‌های تجزیه‌طلب
\item \redcircle\ وجود گروه‌هایی با ادعای «ملت عرب أحواز» 
و درخواست استقلال
\item \yellowcircle\ حملهٔ تروریستی اهواز ۱۳۹۷ و پیامدهای آن
\item \yellowcircle\ آسیب‌پذیری منطقه به‌دلیل نزدیکی مرز عراق
\end{itemize}
\end{casestudy}

\section{جنبش بلوچ}

\begin{casestudy}{جنبش بلوچ — محروم‌ترین اقلیت}
\textbf{جمعیت:} ≈ ۱.۵–۲ میلیون نفر\\
\textbf{طیف:} از حقوق مدنی تا اسلام‌گرایی مسلحانه\\
\textbf{گروه‌های اصلی:}\\
\begin{itemize}[itemsep=1mm]
\item \textbf{فعالان مدنی بلوچ:} مطالبات حقوق فرهنگی، توسعه\\
\item \textbf{مولوی عبدالحمید:} رهبر مذهبی سنّی، نفوذ بالا، 
مواضع میانه‌رو
\item \textbf{جیش‌العدل:} \textcolor{AccentRed}{گروه مسلح 
سلفی-جهادی، اقدامات تروریستی}
\end{itemize}

\textbf{مسئلهٔ ویژه:} بلوچستان محروم‌ترین استان ایران است. 
فقر، بیکاری، بی‌آبی و تبعیض مذهبی (سنّی در نظام شیعه) 
بستر جذب جوانان به گروه‌های افراطی فراهم کرده.

\textbf{تحول مهم:} نقش مولوی عبدالحمید در جنبش ۱۴۰۱ 
(خطبه‌های حمایتی) نشان‌دهندهٔ ظرفیت بالای رهبری 
غیرخشونت‌آمیز در بلوچستان است.
\end{casestudy}

