% فصل ۲۶ — سازمان مجاهدین و اسلام‌گرایان اپوزیسیون
% ============================================================
\chapter{اسلام‌گرایان اپوزیسیون و سازمان مجاهدین}

\section{سازمان مجاهدین خلق ایران (MEK/PMOI)}

\begin{casestudy}{سازمان مجاهدین خلق — بحث‌برانگیزترین 
نیروی اپوزیسیون}
\textbf{تأسیس:} ۱۳۴۴ (۱۹۶۵)\\
\textbf{رهبری:} مریم رجوی (رئیس‌جمهور خودخوانده)\\
\textbf{طیف:} چپ اسلامی (اعلام‌شده) / فرقه‌ای (منتقدان)\\
\textbf{موقعیت:} تبعید (آلبانی — اشرف ۳)\\
\textbf{ساختار:} شورای ملی مقاومت (NCR) به‌عنوان چتر سیاسی\\
\textbf{ظرفیت نظامی:} \textcolor{AccentOrange}{سابقهٔ نظامی، 
وضعیت فعلی نامشخص}\\[3mm]

\textbf{مواضع اعلام‌شده:}
\begin{itemize}[itemsep=1mm]
\item جمهوری دموکراتیک اسلامی (!)
\item جدایی دین از دولت (ادعای اخیر)
\item طرح ۱۰ ماده‌ای مریم رجوی
\item ادعای پایگاه گسترده در داخل ایران
\end{itemize}

\textbf{نقاط بحث‌برانگیز و مشکل‌ساز:}
\begin{itemize}[itemsep=1mm]
\item \redcircle\ ساختار فرقه‌ای و رهبری شخصیت‌محور
\item \redcircle\ سابقهٔ عملیات نظامی علیه ایران از خاک عراق 
(دوران صدام)
\item \redcircle\ نقش در لو دادن عوامل نفوذی (هم‌پیمان و 
هم‌متهم)
\item \redcircle\ عدم شفافیت مالی و سازمانی
\item \redcircle\ مخالفت گستردهٔ سایر نیروهای اپوزیسیون
\item \yellowcircle\ حمایت‌های لابی‌گرانه در آمریکا و اروپا
\item \yellowcircle\ ادعاهای اطلاعاتی (برنامهٔ هسته‌ای ۲۰۰۲)
\end{itemize}
\end{casestudy}

\begin{warningbox}
\textbf{ارزیابی:} مجاهدین خلق مشکل‌ساز‌ترین بازیگر اپوزیسیون 
از نظر ائتلاف‌سازی هستند. اکثریت قریب‌به‌اتفاق سایر 
نیروهای سیاسی حاضر به همکاری با آنها نیستند. هرگونه 
طرح گذار باید موضع مشخصی نسبت به MEK داشته باشد: 
نه حذف از صحنهٔ سیاسی، بلکه تعریف قواعد بازی که 
شامل تمام بازیگران (از جمله MEK) شود — مشروط به 
پذیرش دموکراسی، شفافیت و خلع‌سلاح.
\end{warningbox}

\section{اصلاح‌طلبان}

\begin{casestudy}{اصلاح‌طلبان — جریان درون‌نظام}
\textbf{ماهیت:} جریان سیاسی درون نظام ج.ا. (نه حزب واحد)\\
\textbf{طیف:} مرکز / اسلام دموکراتیک\\
\textbf{شخصیت‌های شاخص:} محمد خاتمی، میرحسین موسوی 
(حصر)، مهدی کروبی، عبدالله نوری، مصطفی تاجزاده (زندان)\\
\textbf{موقعیت:} داخل (تحت فشار شدید / زندان / حصر)\\
\textbf{پایگاه اجتماعی:} طبقهٔ متوسط شهری (تاریخی)\\[3mm]

\textbf{معضل اصلی:} اصلاح‌طلبان در تقاطع پیچیده‌ای قرار 
دارند:
\begin{itemize}[itemsep=1mm]
\item آیا بخشی از نظام هستند یا اپوزیسیون؟
\item آیا پل ارتباطی هستند یا مانع تغییر؟
\item آیا در حکومت آینده جایگاهی دارند؟
\end{itemize}

\textbf{ارزش استراتژیک:} اصلاح‌طلبان به‌رغم ضعف فعلی، 
یک ظرفیت کلیدی دارند: **شناخت ماشین دولتی از درون**. 
در دوران گذار، این دانش نهادی برای حفظ تداوم خدمات 
عمومی حیاتی است.
\end{casestudy}

\section{نهضت آزادی ایران}

\begin{casestudy}{نهضت آزادی — اسلام دموکراتیک}
\textbf{تأسیس:} ۱۳۴۰ (۱۹۶۱) توسط مهندس بازرگان\\
\textbf{طیف:} مرکز / ملی-مذهبی\\
\textbf{رهبری فعلی:} ابراهیم یزدی (†)، اسماعیل سلیمانی\\
\textbf{موقعیت:} داخل (نیمه‌فعال)\\[3mm]

\textbf{اهمیت:} نهضت آزادی نشان‌دهندهٔ امکان «اسلام 
سازگار با دموکراسی» است. این تجربه برای مدیریت تعارض 
دین‌ودولت در دوران گذار ارزشمند است.

\textbf{آمادگی ائتلاف:} بالا — سابقهٔ طولانی در گفتگو با 
طیف‌های مختلف
\end{casestudy}


