% فصل ۲۷ — جنبش‌های نوین و فراحزبی
% ============================================================
\chapter{جنبش‌های نوین: زن زندگی آزادی و فراتر}

\section{جنبش «زن، زندگی، آزادی»}

\begin{casestudy}{جنبش زن زندگی آزادی — نقطهٔ عطف تاریخی}
\textbf{آغاز:} شهریور ۱۴۰۱ (سپتامبر ۲۰۲۲) پس از قتل 
ژینا (مهسا) امینی\\
\textbf{ماهیت:} جنبش اجتماعی فراطیفی (نه حزب)\\
\textbf{رهبری:} غیرمتمرکز / بدون رهبر واحد\\
\textbf{پایگاه:} فراگیر (تمام اقشار، اقوام، سنین)\\
\textbf{توان بسیج‌گری:} \textcolor{AccentGreen}{بسیار بالا}\\[3mm]

\textbf{ویژگی‌های منحصر‌به‌فرد:}
\begin{itemize}[itemsep=1mm]
\item \greencircle\ فراقومی: مشارکت همزمان فارس، کرد، آذری، 
بلوچ، عرب
\item \greencircle\ فراطبقاتی: از دانشجو تا کارگر
\item \greencircle\ فراجنسیتی: رهبری زنان با حمایت مردان
\item \greencircle\ فراایدئولوژیک: سکولار و مذهبی کنار هم
\item \greencircle\ دیجیتالی: هماهنگی از طریق شبکه‌های اجتماعی
\end{itemize}

\textbf{چالش‌ها:}
\begin{itemize}[itemsep=1mm]
\item \yellowcircle\ فقدان ساختار سازمانی
\item \yellowcircle\ نبود برنامهٔ سیاسی مشخص
\item \yellowcircle\ آسیب‌پذیری در برابر سرکوب
\item \yellowcircle\ خطر مصادره توسط جریانات خاص
\end{itemize}
\end{casestudy}

\begin{keypoint}
جنبش ژینا نشان داد که **ائتلاف فراگیر ملی** نه‌تنها ممکن، 
بلکه در صحنهٔ خیابان **تحقق یافته** است. چالش اصلی، 
\textbf{نهادینه‌کردن} این ائتلاف خیابانی در قالب‌های 
سیاسی-سازمانی پایدار است.
\end{keypoint}

\section{جنبش کارگری}

\begin{casestudy}{جنبش کارگری — نیروی خاموش}
\textbf{ماهیت:} مجموعه‌ای از سندیکاها و تشکل‌های کارگری\\
\textbf{شخصیت‌ها:} اسماعیل عبدی، رضا شهابی، جعفر عظیم‌زاده 
(همه زندانی یا تحت فشار)\\
\textbf{پایگاه:} کارگران صنعتی، معلمان، بازنشستگان\\
\textbf{ویژگی:} بالاترین ظرفیت فلج‌کردن اقتصاد (اعتصابات)\\[3mm]

\textbf{اهمیت استراتژیک:} اعتصاب نفتگران در ۵۷ ضربهٔ 
نهایی به رژیم شاه بود. اعتصاب سراسری کارگران می‌تواند 
ابزار قاطع در هر سناریوی تغییر باشد.
\end{casestudy}


